solution_code:
#include <iostream>

class Alpha {
public:
    Alpha()  { std::cout << "Alpha constructed\n"; }
    ~Alpha() { std::cout << "Alpha destructed\n"; }
};

class Beta : public Alpha {
public:
    Beta()  { std::cout << "Beta constructed\n"; }
    ~Beta() { std::cout << "Beta destructed\n"; }
};

class Gamma : public Beta {
public:
    Gamma()  { std::cout << "Gamma constructed\n"; }
    ~Gamma() { std::cout << "Gamma destructed\n"; }
};

int main() {
    Gamma g;
    return 0;
}

